var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"모, 모네는 살면서 저런 건 실제로 처음 봤슴다!","JPN":"モ、モネはあんなの初めてみるっす！","ENG":"M-Mone has never seen anything like this before, ma’am!","TWN":"莫…莫妮活到現在，第一次看到那樣的東西唷！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"세상에……. 태풍은 많이 봤어도 토네이도 얘기는 들은 적 없는데…….","JPN":"そんな……台風はあってもトルネードがこの村に発生した話は聞いたことがありません……","ENG":"Oh no... We’ve had storms before, but never a tornado...","TWN":"天啊……雖然經歷過很多次颱風，但龍捲風我還是第一次聽說呢…"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"오오, 나 몸이 점점 밀려나, 아빠!","JPN":"おお、身体が押されてるよ、パパ！","ENG":"Daddy, I’m getting pushed away, wow!","TWN":"哦哦，爸爸！我好像快飛走咧！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"맞다! 저걸 타고 날아가면 마법의 대륙으로 떠날 수 있을까?","JPN":"そうだ！　あれに乗って飛んでいけば魔法の大陸に行けるのかな？","ENG":"Maybe this tornado will take me to another magical world!","TWN":"哇！乘著那個是不是可以直接飛上月球？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아니, 그건 착한 토네이도가 하는 일이란다. 저건 사람을 해치는 아주 나쁜 토네이도야.","JPN":"いや、それは善良なトルネードがすることだよ。あれは人を傷つける非常に悪いトルネードだ。","ENG":"No, that’s what a good tornado does. This is a bad tornado that hurts people.","TWN":"不，上月球要搭阿波羅11號，而且龍捲風只會搞破壞。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"사람을 해쳐? 그런 건 싫어!","JPN":"人を傷つける？　そんなのイヤだよ！","ENG":"It hurts people? No!","TWN":"搞破壞？我不喜歡搞破壞！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"움직이는 속도가 무척 빠르군요. 저대로 두면 마을을 그대로 덮치겠습니다.","JPN":"速度がとても速いです。このままだと、村を直撃するでしょう。","ENG":"It’s coming in fast. It will hit the village soon.","TWN":"移動的速度好快，放著不管的話，恐怕會直撲村莊。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"으음……. 가장 안 좋은 예상이 맞아떨어졌군.","JPN":"ううむ……不吉な予感が的中してしまったな。","ENG":"Um... this is the worst case scenario...","TWN":"呃…真是屋漏偏逢連夜雨。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"드라코! 저건 <color=#ffd34c>그거</color> 때문이죠?! 기상조절 시스템!","JPN":"ドラコ！　あれは<color=#ffd34c>アレ</color>のせいですね！？　気象調節システム！","ENG":"Dracasia! It’s because of <color=#ffd34c>that</color> thing, right? The Weather Control System!","TWN":"德拉克！是因為<color=#ffd34c>那個</color> 吧？！氣象調節系統！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"맞아. 쓰지 말라고 했는데 결국에는 이 꼴이 나 버렸어.","JPN":"そうだよ。使うなって言ったのに結局この様だ。","ENG":"Yes. I told them not to use it, yet here we are.","TWN":"沒錯。我有說過不要用，結果還是這樣。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"돈만 많은 멍청이들 같으니…….","JPN":"脳みそに金しか入ってないバカな連中……","ENG":"Those rich, arrogant idiots...","TWN":"那群有錢就是任性的傢伙…"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"기상조절 시스템? 그건 관리국 직할 도시에만 설치된 물건 아닌가요?","JPN":"気象調節システム？　それは管理局直轄都市にだけ設置された物ではないのですか？","ENG":"The Weather Control System? That device is installed only in Administration Direct Control Cities, right?","TWN":"氣象調節系統？那東西不是只設置在管理局直轄市嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그러고 보니 최근에 마크…… 아니, 아는 사람한테서 들은 적이 있어.","JPN":"そういえば最近マーク……いや、知り合いから聞いたことある。","ENG":"Mark—I mean someone I know told me told me recently...","TWN":"這麼說來，馬克……不是，我好像聽朋友說過。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그로니아 반군이 샤레이드에 설치하려고 했던 기상조절 시스템을 탈취했다나 봐.","JPN":"グロニア反乱軍がシャレードに設置しようとしていた気象調節システムを奪取したみたい。","ENG":"Gronia rebels stole the Weather Control System that was originally meant for Charade.","TWN":"原本要設置在查雷德的氣象調節系統，似乎落入格羅尼亞叛軍的手裡。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"군자금을 마련하려고 블랙 네트워크를 통해 판매했나 보군요.","JPN":"軍資金を調達しようとブラックネットワークを通じて販売したようですね。","ENG":"Then they sold it through the Dark Network to fund their operations.","TWN":"很可能是因為要籌措軍事費用，才會透過黑色網絡出售。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 저렇게 위험한 물건을 겨우 돈 몇 푼 때문에 아무한테나 넘기다니…….","JPN":"しかし、あんなに危険な物をわずかなお金のために一般人に渡すなんて……","ENG":"They shouldn’t be selling so dangerous a device just for money...","TWN":"但他們竟然為了幾個錢，就把那麼危險的東西輕易給出去……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그, 그럼 어떻게 해야 저 커다란 꽈배기를 막을 수 있음까?","JPN":"じゃ、じゃあ、どうすればあのでっかいくねくねを倒せるんっすか？","ENG":"W-what should we do to stop that huge twister, ma’am?","TWN":"那…現在該怎麼阻止那個大麻花捲呢？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"포기해. 이미 작동시킨 이상 다 틀렸어.","JPN":"諦めな。もう作動させた以上、何しても無駄だ。","ENG":"Don’t bother. It’s all over now.","TWN":"放棄吧，現在已經是覆水難收。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"지금 당장 튀는 게 좋을걸. 마을에 도착할 즈음이면 저것보다 몇 배는 더 커질 테니까.","JPN":"今すぐ逃げたほうが身のためだ。村に到着する頃には、あれより何倍も大きくなるはずだから。","ENG":"We have to run. That thing will get much bigger by the time when it gets to the village.","TWN":"勸你們還是趕快逃吧！等到快要接近村莊時，可能會比現在還大好幾倍喔。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그럴 수는 없슴다! 모네가 반드시 막아 볼 검다!","JPN":"そうはいかないっす！　モネが何としても止めてみせるっす！","ENG":"I can’t let that happen, ma’am! Mone will stop that thing!","TWN":"我不！莫妮一定要擋下那個大麻花捲！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"모네야!","JPN":"モネ！","ENG":"Mone!","TWN":"莫妮！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"어, 엄니…….","JPN":"か、母ちゃん……","ENG":"M-mama...","TWN":"媽…媽媽…"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"이제 괜찮아. 우리 모네, 충분히 애썼잖니.","JPN":"もういいのよ。モネ、私たちみんな、もう十分頑張ったわ。","ENG":"It’s okay, Mone. You already did your best.","TWN":"沒關係的，你已經盡力了。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"어서 짐을 싸서 피해야 해. 움직이기 힘드신 어르신들도 계시니까 도와 드리렴.","JPN":"早く荷物をまとめて逃げないと。身体が不自由な高齢者もいるから手伝ってあげなさい。","ENG":"We have to pack. We also have to help the elders to evacuate.","TWN":"我們趕快收拾好行李離開吧。還要去幫忙那些行動不便的長輩呢。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그, 그치만 엄니도 아부지도 어르신들도 전부 여길 좋아하지 않슴까!","JPN":"で、でも、母ちゃんも父ちゃんも村のみんなも、この村が大好きなんじゃないっすか？","ENG":"But mama, papa, and everyone else love this village!","TWN":"可…可是媽媽…爸爸，還有長輩們，都很喜歡這裡不是嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"못된 사람들 때문에 엄니랑 어르신들이 쫓겨나는 건 싫슴다!","JPN":"悪い人たちのせいで母ちゃんとみんなが追い出されるのはイヤっす！","ENG":"I can’t let these mean people drive you away!","TWN":"我不希望媽媽和長輩們被那些壞人趕出去！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"흑……. 흐윽…….","JPN":"ぐすん……ううっ……","ENG":"*Sob*","TWN":"嗚…嗚嗚…"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"모네야…….","JPN":"モネ……","ENG":"Mone...","TWN":"莫妮…"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"엄마가 미안해. 가진 것 없고 배운 것도 없어서……. 정말 미안해…….","JPN":"ごめんね。お母さんにお金も地位もなくて……本当にごめんね……","ENG":"I’m so sorry, Mone. I cannot help you. There’s nothing I can do... I’m so sorry...","TWN":"媽媽對不起你，家裡能給你的不多…都怪我們不好…"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"그러니까 뚝 하자, 응?","JPN":"だから泣かないで、イイ子でしょう？","ENG":"Please stop crying. Hmm?","TWN":"所以不要哭，嗯？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아뇨. 모네 양 말이 맞습니다, 어머님.","JPN":"いいえ、モネの言うとおりです、お母さん。","ENG":"Ma’am, Mone’s right.","TWN":"不，伯母，莫妮說的對。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어머님도 고향을 사랑하시지 않습니까. 포기하시기엔 아직 일러요.","JPN":"お母さんもこの村を愛しているでしょう。諦めるにはまだ早いです。","ENG":"I know you love your hometown. We can’t give up just yet.","TWN":"伯母很愛這個地方不是嗎？現在放棄還言之過早。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"……사장님, 이제부터는 저희 손을 떠난 일이에요.","JPN":"……社長、ここからは私たちの力ではどうにもならないことです。","ENG":"... But this is beyond us.","TWN":"…老闆，我們已經無能為力了。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"희망을 주시려는 마음은 이해하지만, 그럴수록 모네도 실망이 커질 거예요.","JPN":"希望を与えてくださるお気持ちはありがたいですが、そうすればするほどモネの失望も大きくなるでしょう。","ENG":"I understand you’re trying to be hopeful, but it will only bring greater disappointment.","TWN":"我明白老闆不想傷害莫妮的心，但期待越大，失望也越大。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어머님, 사업 하는 사람은 지킬 수 있는 말만 해야 합니다.","JPN":"お母さん、事業に携わる人間は守れる約束のみしなければなりません。","ENG":"Ma’am, a businessman should never make empty promises.","TWN":"伯母，做生意的人言出必行。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"저쪽이 비장의 패를 꺼냈으니 우리도 그에 걸맞은 패를 꺼내야죠.","JPN":"向こうが切り札を出してきたのであれば、我々もそれにふさわしいカードを出さなければなりません。","ENG":"We have no choice but to play our ace card now.","TWN":"既然對方已經秀出底牌，現在該我們出牌囉！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"무슨…… 말씀이시죠?","JPN":"何を……おっしゃっているのかしら？","ENG":"What are you talking about?","TWN":"這是…什麼意思？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"설명하긴 조금 어렵긴 한데……","JPN":"説明するのは少し難しいのですが……","ENG":"It’s a bit difficult to explain...","TWN":"有點說來話長…"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아. 마침 시간이 다 됐군요.","JPN":"ああ、ちょうど時間ですね。","ENG":"Oh, it’s almost time.","TWN":"喔！時間剛剛好！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"플라티나 익스프레스 앱을 이용해 주셔서 감사합니다, 고객님!","JPN":"プラチナエクスプレスをご利用いただき誠にありがとうございます、お客様！","ENG":"Thank you for using Platina Express!","TWN":"感謝客人使用白金運通！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_CAR_SKID"},{"id":"L12_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"약속 시간에는 안 늦었죠? 샤레이드 쪽에 밀려 있던 일감을 전부 처리하느라 바빴거든요!","JPN":"約束の時間には間に合いましたかね？　シャレードの方に溜まっていた仕事の対応で忙しかったんですよ！","ENG":"Am I late? I’ve been busy taking care of leftover tasks in Charade!","TWN":"我有在約定時間內抵達吧？因為我正忙著處理查雷德那邊拖延的案件！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"으헉?! 마을에 펭귄들이 왜 이렇게 많아요?!","JPN":"え！？　どうしてペンギンがこんなにたくさんいるんですか？","ENG":"Heek! What’s up with all these penguins?","TWN":"呃？！村裡怎麼會這麼多企鵝？！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"예거 양, 자네가 여기 마을 사람들을 위해 한 가지 해 줬으면 하는 일이 있다네.","JPN":"イェーガーさん、ここの村人たちのために君に一つ頼みたいことがある。","ENG":"Ms. Jaegar, there’s something I would like to ask you for this village.","TWN":"伊格，我希望你能為這裡的居民做一件事。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"네? 어떤 일인데요?","JPN":"はい？　どんな仕事ですか？","ENG":"Yes? What is it?","TWN":"嗯？什麼事呢？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"저 토네이도랑 반대 방향으로 돌아서 바람을 멈춰 주게.","JPN":"あのトルネードの反対方向に回って風を止めてくれ。","ENG":"I would like you to spin the opposite direction to the tornado to stop it.","TWN":"就是往那個龍捲風的反方向跑，讓龍捲風停下來。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"저기 고객님, 죄송한데 주문 내용을 다시 말씀해 주시겠어요?","JPN":"あの、お客様、申し訳ございませんがご注文の内容をもう一度おっしゃっていただけますか？","ENG":"Sir, could you please repeat the request?","TWN":"客人，不好意思，可以再重複一遍訂單內容嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"사장님께선 당신만 할 수 있는 일이기 때문에 부탁하시는 겁니다.","JPN":"社長はあなたしかできないことを依頼しているのです。","ENG":"He’s asking you because only you can do this.","TWN":"老闆認為這件事非你不可，所以才拜託你的。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"단거리 공간 도약을 통해 가속하는 고속 능력자는 무척 드무니까요.","JPN":"短距離空間跳躍によって加速する高速能力者はとても希少ですから。","ENG":"A Counter with a short distance space jumping ability like yours is very rare.","TWN":"因為透過近距空間跳耀來加速的高速能力者是非常少見的。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"어?! 그걸 어떻게 아셨어요?! 특급 영업 비밀이라고 회사에서 절대 말하지 말랬는데?!","JPN":"あれ？　なんでわかったんですか？　特級企業秘密だから会社から絶対内緒でって言われたのに！？","ENG":"Huh?! How did you know? The company forbade to mention it because it’s a trade secret!","TWN":"哦？！你怎麼知道的？！公司說這是內部最高機密，要我絕對不能說欸？！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"처음 봤을 때부터 알아차렸습니다. 예전 동료 중에 동일한 능력을 가진 분이 계셨거든요.","JPN":"初めて会った時から気付いていました。昔の同僚に同じ能力を持った方がいたんです。","ENG":"I recognized your ability when I first saw you using it. One of my colleagues had the same ability.","TWN":"第一次見面時就察覺到了，因為以前的同事中，也有一位具有相同的能力。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"푸하아! 덕분에 살았어요, 사모님!","JPN":"ぷはー！　おかげで助かりました、奥様！","ENG":"Phew! You saved my life, missus!","TWN":"噗哈！謝謝老闆娘救命之恩！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_DIVE_EATER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"별말씀을. <color=#ffd34c>그런 능력</color>을 가지고도 당할 거라고 예상 못 한 제 책임이 크니까요.","JPN":"いいえ。<color=#ffd34c>そんな能力</color>を持っているのにやられると予想できなかった私の責任もありますから。","ENG":"You’re welcome. I didn’t expect you’d let them get you even with <color=#ffd34c>your ability</color>. That was my fault.","TWN":"不用客氣。都怪我不好，沒預料到擁有那種能力還打不過企鵝。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_DIVE_EATER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"설마 그 능력으로 싸울 줄 모를 거라고는 상상도 못했지만요.","JPN":"まさか、その能力を持っていて戦えないとは想像もできませんでしたが。","ENG":"Well, I didn’t expect you to be so helpless in combat with an ability like that, though.","TWN":"只是我沒想到，這個能力竟然沒被運用在戰鬥上。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"그, 그래도…….","JPN":"で……でも……","ENG":"B-but still...","TWN":"可…可是…"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네! 모네!","JPN":"モネ！　モネ！","ENG":"Mone! Mone!","TWN":"莫妮！莫妮！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네네!","JPN":"モネネ！","ENG":"Monene!","TWN":"莫妮妮！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GRANDMA_NPC_SUMMER_NULL","text":{"KOREA":"아이고, 얘들이 짐을 다 들어 주네.","JPN":"まあ、優しい子じゃな。荷物まで全部持ってくれてありがたや。","ENG":"Oh, they are moving our bags for us.","TWN":"哎呀，謝謝你們還幫我拿行李。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GRANDFA_NPC_SUMMER_NULL","text":{"KOREA":"저기, 저쪽 어르신부터 옮겨야 돼. 다리가 불편하셔서…….","JPN":"あそこのお家の荷物も頼んでいいかね。足が悪い人の家で……","ENG":"You have to help that granny over there. She can’t walk by herself...","TWN":"他先走吧，他的腳不太方便……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GRANDMA_NPC_SUMMER_NULL","text":{"KOREA":"이대로 어디를 가나……. 차라리 여기서 죽는 게 낫지…….","JPN":"これからどこに行けば……ここで死んだ方が……","ENG":"Where do we go now? I would rather die here...","TWN":"我還能去哪裡…… 我情願死在這裡……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"읏…….","JPN":"うっ……","ENG":"Ugh...","TWN":"唔……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"알겠습니다! 해 볼게요!","JPN":"わかりました！　やってみます！","ENG":"Okay, I’ll try!","TWN":"好吧！我來試試吧！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"맑은 날씨 배달 주문! 접수했습니다!","JPN":"晴天配達注文！　受注しました！","ENG":"Your request for clear weather, acknowledged!","TWN":"訂單內容：龍捲風去去走！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};